Here are the public test cases for feature7_user_agent_flags:
{
  "description": "Parse repeated user-agent command-line flags into ordered user-agent values, preserving spaces inside a flag value and reporting a normalized flag error when a value is missing.",
  "cases": [
    {
      "input": {
        "user_agent_flags": []
      },
      "expected_output": "user_agents=\n"
    },
    {
      "input": {
        "user_agent_flags": [
          "--user-agent=cluster/abc-123"
        ]
      },
      "expected_output": "user_agents=cluster/abc-123\n"
    },
    {
      "input": {
        "user_agent_flags": [
          "--user-agent=a/b",
          "--user-agent=c/d"
        ]
      },
      "expected_output": "user_agents=a/b,c/d\n"
    },
    {
      "input": {
        "user_agent_flags": [
          "--user-agent=a b"
        ]
      },
      "expected_output": "user_agents=a b\n"
    },
    {
      "input": {
        "user_agent_flags": [
          "--user-agent=a",
          "b"
        ]
      },
      "expected_output": "user_agents=a\n"
    },
    {
      "input": {
        "user_agent_flags": [
          "--user-agent"
        ]
      },
      "expected_output": "error=invalid_flags\n"
    }
  ]
}
